.darma-loader-uiverse-splash-square-trio {
  display: flex;
  gap: 8px;
  justify-content: center;
  align-items: center;
  height: 60px;
}

/* Individual squares */
.darma-loader-uiverse-splash-square-trio__square {
width: 22px;
height: 22px;
background-color: rgb(0, 247, 255);
border-radius: 4px;
box-shadow: 0 0 12px rgba(4, 136, 252, 0.8);
animation: darma-loader-uiverse-darma-loader-uiverse-splash-square-trio-splash-square-trio-scaleBounce 1.2s infinite ease-in-out;
position: relative;
}

/* Splash effect */
.darma-loader-uiverse-splash-square-trio__square::after {
content: "";
position: absolute;
width: 100%;
height: 100%;
background-color: rgba(0, 247, 255, 0.5);
border-radius: 50%;
opacity: 0;
transform: scale(1);
animation: darma-loader-uiverse-splash-square-trio-splash 1.2s infinite ease-in-out;
}

/* Animations for each square */
.darma-loader-uiverse-splash-square-trio__square:nth-child(1) {
animation-delay: -0.4s;
}
.darma-loader-uiverse-splash-square-trio__square:nth-child(2) {
animation-delay: -0.2s;
}
.darma-loader-uiverse-splash-square-trio__square:nth-child(3) {
animation-delay: 0s;
}

@keyframes darma-loader-uiverse-splash-square-trio-scaleBounce {
0%,
80%,
100% {
transform: scale(0.5);
opacity: 0.6;
}
40% {
transform: scale(1.2);
opacity: 1;
}
}

@keyframes darma-loader-uiverse-splash-square-trio-splash {
0% {
opacity: 0.6;
transform: scale(1);
}
50% {
opacity: 0;
transform: scale(2);
}
100% {
opacity: 0;
transform: scale(2.5);
}
}
